import { Collapsible as CollapsiblePrimitive } from '@base-ui/react/collapsible';
import { clsx } from 'clsx';
import { forwardRef, type ComponentProps, type ComponentRef } from 'react';
import { ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Collapsible.module.css';

const Collapsible = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Root>,
  CollapsiblePrimitive.Root.Props
>(function Collapsible({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Root
      ref={ref}
      data-slot="collapsible-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

const CollapsibleTrigger = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Trigger>,
  CollapsiblePrimitive.Trigger.Props
>(function CollapsibleTrigger({ className, render, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Trigger
      ref={ref}
      data-slot="collapsible-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
});

function CollapsibleTriggerIcon({
  className,
  children,
  'aria-hidden': ariaHidden = true,
  ...props
}: ComponentProps<'span'>) {
  return (
    <span
      data-slot="collapsible-trigger-icon"
      aria-hidden={ariaHidden}
      className={clsx(styles.triggerIcon, className)}
      {...props}
    >
      {children ?? <ChevronRightIcon />}
    </span>
  );
}

const CollapsiblePanel = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Panel>,
  CollapsiblePrimitive.Panel.Props
>(function CollapsiblePanel({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Panel
      ref={ref}
      data-slot="collapsible-panel"
      className={mergeClassName(className, styles.panel)}
      {...props}
    />
  );
});

export { Collapsible, CollapsibleTrigger, CollapsibleTriggerIcon, CollapsiblePanel };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--collapsible-width, 14rem);
    max-width: var(--collapsible-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    color: var(--collapsible-color, var(--color-foreground));
  }

  .trigger {
    box-sizing: border-box;
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: space-between;
    gap: var(--collapsible-trigger-gap, var(--spacing-2));
    margin: 0;
    border: 0;
    border-radius: var(--collapsible-trigger-radius, 0);
    padding-block: var(--collapsible-trigger-padding-y, var(--spacing-1));
    padding-inline: var(--collapsible-trigger-padding-x, var(--spacing-2));
    background-color: var(--collapsible-trigger-bg, transparent);
    color: var(--collapsible-trigger-color, var(--collapsible-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--collapsible-trigger-font-size, var(--text-sm));
    line-height: var(--collapsible-trigger-line-height, var(--line-height-text-sm));
    text-align: left;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--collapsible-trigger-transition, var(--transition-default)),
      color var(--collapsible-trigger-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover:not([disabled]):not([data-disabled]) {
        background-color: var(
          --collapsible-trigger-bg-hover,
          var(--collapsible-trigger-bg, transparent)
        );
      }
    }

    &:active:not([disabled]):not([data-disabled]) {
      background-color: var(
        --collapsible-trigger-bg-active,
        var(--collapsible-trigger-bg-hover, var(--collapsible-trigger-bg, transparent))
      );
    }

    &:focus-visible {
      outline: var(--collapsible-focus-ring-width, var(--border-width-sm)) solid
        var(--collapsible-focus-ring-color, var(--color-ring));
      outline-offset: var(--collapsible-focus-ring-offset, var(--border-width-sm));
    }

    &[disabled],
    &[data-disabled] {
      opacity: var(--collapsible-disabled-opacity, var(--opacity-disabled));
      cursor: default;
    }
  }

  .triggerIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--collapsible-icon-size, 0.75rem);
    height: var(--collapsible-icon-size, 0.75rem);
    flex-shrink: 0;
    transition: transform var(--collapsible-icon-transition, var(--transition-default));

    & > svg {
      width: 100%;
      height: 100%;
    }

    [data-panel-open] & {
      transform: var(--collapsible-icon-open-transform, rotate(90deg));
    }
  }

  .panel {
    box-sizing: border-box;
    height: var(--collapsible-panel-height);
    overflow: hidden;
    color: var(--collapsible-panel-color, var(--color-muted-foreground));
    font-size: var(--collapsible-panel-font-size, var(--text-sm));
    line-height: var(--collapsible-panel-line-height, var(--line-height-text-sm));
    transition: height var(--collapsible-panel-transition, var(--transition-default));

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }

    &[data-starting-style],
    &[data-ending-style] {
      height: 0;
    }
  }
}

export {
  Collapsible,
  CollapsibleTrigger,
  CollapsibleTriggerIcon,
  CollapsiblePanel,
} from './Collapsible';
